INSERT INTO `pages` (`id`, `title`, `slug`, `content`, `thumbnail`, `status`, `created_at`, `updated_at`) VALUES (13, 'Privacy Policy', 'privacy-policy', '<p></p><h2><span style=\"font-size: 18px;\">Privacy Policy</span></h2><h2><br></h2><h2><span style=\"font-size: 18px;\">Selamat datang di NazmuBlog.</span></h2><h2><br></h2><h2><span style=\"font-size: 18px;\">Kami menghargai privasi pengunjung website ini. Informasi pribadi yang dikumpulkan hanya digunakan untuk meningkatkan pengalaman pengguna dan pelayanan website.</span></h2><h2><br></h2><h2><span style=\"font-size: 18px;\">Informasi yang Dikumpulkan</span></h2><h2><br></h2><h2><span style=\"font-size: 18px;\">- Data browser</span></h2><h2><span style=\"font-size: 18px;\">- Alamat IP</span></h2><h2><span style=\"font-size: 18px;\">- Cookie</span></h2><h2><span style=\"font-size: 18px;\">- Data analitik pengunjung</span></h2><h2><br></h2><h2><span style=\"font-size: 18px;\">Google AdSense</span></h2><h2><br></h2><h2><span style=\"font-size: 18px;\">Website ini dapat menggunakan layanan iklan pihak ketiga seperti Google AdSense yang menggunakan cookie untuk menampilkan iklan relevan.</span></h2><h2><br></h2><h2><span style=\"font-size: 18px;\">Pengguna dapat menonaktifkan personalized ads melalui pengaturan Google Ads.</span></h2><h2><br></h2><h2><span style=\"font-size: 18px;\">Keamanan Data</span></h2><h2><br></h2><h2><span style=\"font-size: 18px;\">Kami menjaga keamanan data pengguna dan tidak membagikan informasi pribadi tanpa izin.</span></h2><h2><br></h2><h2><span style=\"font-size: 18px;\">Perubahan Kebijakan</span></h2><h2><br></h2><h2><span style=\"font-size: 18px;\">Kebijakan privasi dapat diperbarui sewaktu-waktu.</span></h2><p></p>', NULL, 1, '2026-05-16 07:52:03', '2026-05-16 07:57:33');
INSERT INTO `pages` (`id`, `title`, `slug`, `content`, `thumbnail`, `status`, `created_at`, `updated_at`) VALUES (14, 'Disclaimer', 'disclaimer', '<div>Disclaimer</div><div><br></div><div>Seluruh informasi di website ini dipublikasikan dengan itikad baik dan untuk tujuan informasi umum.</div><div><br></div><div>Kami tidak memberikan jaminan terkait kelengkapan, keakuratan, dan keandalan informasi.</div><div><br></div><div>Segala tindakan yang dilakukan berdasarkan informasi di website ini merupakan tanggung jawab pengguna sepenuhnya.</div><div><br></div><div>Website ini mungkin mengandung tautan ke situs eksternal yang tidak berada di bawah kendali kami.</div>\r\n', NULL, 1, '2026-05-16 07:54:44', '2026-05-16 07:54:44');
INSERT INTO `pages` (`id`, `title`, `slug`, `content`, `thumbnail`, `status`, `created_at`, `updated_at`) VALUES (15, 'Terms & Conditions', 'terms-conditions', '<div>Terms & Conditions</div><div><br></div><div>Dengan mengakses website ini, Anda dianggap menyetujui seluruh syarat dan ketentuan yang berlaku.</div><div><br></div><div>Penggunaan Konten</div><div><br></div><div>Konten website tidak boleh disalin, didistribusikan, atau digunakan tanpa izin.</div><div><br></div><div>Tanggung Jawab Pengguna</div><div><br></div><div>Pengguna bertanggung jawab atas aktivitas yang dilakukan saat menggunakan website.</div><div><br></div><div>Perubahan Layanan</div><div><br></div><div>Kami berhak mengubah atau menghentikan layanan kapan saja tanpa pemberitahuan.</div>\r\n', NULL, 1, '2026-05-16 07:56:00', '2026-05-16 07:57:15');


#
# TABLE STRUCTURE FOR: posts
#

DROP TABLE IF EXISTS `posts`;

CREATE TABLE `posts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `category_id` int(11) DEFAULT NULL,
  `user_id` int(11) DEFAULT NULL,
  `title` varchar(255) NOT NULL,
  `slug` varchar(255) NOT NULL,
  `meta_title` varchar(255) DEFAULT NULL,
  `meta_description` text,
  `thumbnail` varchar(255) DEFAULT NULL,
  `excerpt` text,
  `content` longtext,
  `status` enum('draft','publish') DEFAULT 'draft',
  `views` int(11) DEFAULT '0',
  `published_at` datetime DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `slug` (`slug`),
  KEY `fk_category` (`category_id`),
  CONSTRAINT `fk_category` FOREIGN KEY (`category_id`) REFERENCES `categories` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=latin1;

