INSERT INTO `posts` (`id`, `category_id`, `user_id`, `title`, `slug`, `meta_title`, `meta_description`, `thumbnail`, `excerpt`, `content`, `status`, `views`, `published_at`, `created_at`, `updated_at`) VALUES (3, 1, 1, 'Judul artikel ketiga', 'judul-artikel-ketiga-2', 'ringkasa ketiga', 'berita heboh', '4a7d65f7c71940faeb7a770df5822c76.jpeg', 'ini ringkasan artikel ketiga', '\r\n\r\n<h2 style=\"margin: 0px 0px 10px; padding: 0px; font-family: DauphinPlain; font-size: 24px; line-height: 24px; color: rgb(0, 0, 0);\">Where does it come from?</h2><p style=\"margin: 0px 0px 15px; padding: 0px; text-align: justify; color: rgb(0, 0, 0); font-family: \"Open Sans\", Arial, sans-serif; font-size: 14px;\">Contrary to popular belief, Lorem Ipsum is not simply random text. It has roots in a piece of classical Latin literature from 45 BC, making it over 2000 years old. Richard McClintock, a Latin professor at Hampden-Sydney College in Virginia, looked up one of the more obscure Latin words, consectetur, from a Lorem Ipsum passage, and going through the cites of the word in classical literature, discovered the undoubtable source. Lorem Ipsum comes from sections 1.10.32 and 1.10.33 of \"de Finibus Bonorum et Malorum\" (The Extremes of Good and Evil) by Cicero, written in 45 BC. This book is a treatise on the theory of ethics, very popular during the Renaissance. The first line of Lorem Ipsum, \"Lorem ipsum dolor sit amet..\", comes from a line in section 1.10.32.</p><p style=\"margin: 0px 0px 15px; padding: 0px; text-align: justify; color: rgb(0, 0, 0); font-family: \"Open Sans\", Arial, sans-serif; font-size: 14px;\">The standard chunk of Lorem Ipsum used since the 1500s is reproduced below for those interested. Sections 1.10.32 and 1.10.33 from \"de Finibus Bonorum et Malorum\" by Cicero are also reproduced in their exact original form, accompanied by English versions from the 1914 translation by H. Rackham.</p>\r\n\r\n', 'publish', 14, '2026-05-13 13:35:37', '2026-05-13 20:35:25', '2026-05-16 09:27:36');


#
# TABLE STRUCTURE FOR: scrap_ijazah_logs
